0	/**
1	 * Sovereign Systems Spiral — Canvas Renderer
2	 *
3	 * Vanilla Canvas API implementation with 2D Perlin noise for organic orbital motion.
4	 * No dependencies. Targets 60fps with 4 pillar nodes, orbital arcs, and a logarithmic
5	 * spiral line. Desktop only — mobile gets SpiralFallback.astro (CSS-only).
6	 */
7	
8	// ---------------------------------------------------------------------------
9	// Types
10	// ---------------------------------------------------------------------------
11	
12	interface PillarData {
13	  name: string;
14	  slug: string;
15	  emoji: string;
16	  tagline: string;
17	  color: string;
18	  url: string;
19	  status: 'live' | 'coming-soon';
20	  order: number;
21	}
22	
23	// ---------------------------------------------------------------------------
24	// 2D Perlin Noise (minimal implementation)
25	// ---------------------------------------------------------------------------
26	
27	const PERM = new Uint8Array(512);
28	const GRAD = [
29	  [1, 1], [-1, 1], [1, -1], [-1, -1],
30	  [1, 0], [-1, 0], [0, 1], [0, -1],
31	];
32	
33	function initNoise(): void {
34	  const p = new Uint8Array(256);
35	  for (let i = 0; i < 256; i++) p[i] = i;
36	  for (let i = 255; i > 0; i--) {
37	    const j = Math.floor(Math.random() * (i + 1));
38	    [p[i], p[j]] = [p[j], p[i]];
39	  }
40	  for (let i = 0; i < 512; i++) PERM[i] = p[i & 255];
41	}
42	
43	function fade(t: number): number {
44	  return t * t * t * (t * (t * 6 - 15) + 10);
45	}
46	
47	function lerp(a: number, b: number, t: number): number {
48	  return a + (b - a) * t;
49	}

1	---
2	import { getCollection } from 'astro:content';
3	import Base from '../../layouts/Base.astro';
4	import CTAButton from '../../components/CTAButton.astro';
5	import ComingSoon from '../../components/ComingSoon.astro';
6	import ResearchAccordion from '../../components/ResearchAccordion.astro';
7	import VerticalSpine from '../../components/VerticalSpine.astro';
8	import EmailGate from '../../components/EmailGate.astro';
9	import { config } from '../../data/hub.config';
10	
11	export async function getStaticPaths() {
12	  const branches = await getCollection('branches');
13	  return branches.map((branch) => ({
14	    params: { slug: branch.id.replace(/\.md$/, '') },
15	    props: { branch },
16	  }));
17	}
18	
19	const { branch } = Astro.props;
20	const { Content } = await branch.render();
21	const { title, emoji, hook, status, tone } = branch.data;
22	const ctaLabel = tone === 'soft' ? 'Explore gently' : 'Start with your water';
23	
24	const branchConfig = config.branches.find(b => b.slug === branch.id.replace(/\.md$/, ''));
25	const citationIds = branchConfig?.citationIds || [];
26	---
27	
28	<Base title={`${title} — Water`}>
29	  <VerticalSpine />
30	  <!-- Branch header — FREE (Layer 1) -->
31	  <section class="relative min-h-[60vh] flex flex-col items-center justify-center text-center px-6 py-24 glow-bg overflow-hidden">
32	    <div class="relative text-6xl mb-6">{emoji}</div>
33	    <h1 class="relative font-heading text-[clamp(40px,5vw,64px)] font-light text-white leading-[1.1] mb-6" style="text-shadow: 0 0 50px rgba(17,154,158,0.12);">
34	      {title}
35	    </h1>
36	    <p class="relative font-heading italic text-white/45 text-[clamp(18px,2.5vw,24px)] leading-relaxed max-w-2xl">
37	      {hook}
38	    </p>
39	  </section>
40	
41	  <!-- Deep content — GATED (Layer 2) -->
42	  <div class="divider-line"></div>
43	  <section class="py-16 px-6 bg-ocean-900">
44	    <div class="max-w-[640px] mx-auto">
45	      {status === 'placeholder' ? (
46	        <ComingSoon title={title} emoji={emoji} />
47	      ) : (
48	        <EmailGate preview={`Research-backed deep dive into ${title.toLowerCase()} — what it means, where water fits, and what the science shows.`}>
49	          <div class="branch-content text-[16px] leading-[1.9]">
50	            <Content />
51	          </div>
52	          <ResearchAccordion ids={citationIds} />
53	        </EmailGate>
54	      )}
55	    </div>
56	  </section>
57	
58	  <!-- CTA — FREE (visible to drive conversion) -->
59	  <section class="py-20 px-6 glow-bg text-center border-t border-ocean-500/10">
60	    <div class="relative flex flex-col sm:flex-row gap-4 justify-center items-center">
61	      <CTAButton href={config.ghl.productUrl} label={ctaLabel} />
62	      <CTAButton href="/water/explore" label="Explore other branches" variant="secondary" />
63	    </div>
64	  </section>
65	</Base>
